/// <reference path="./online-streaming-provider.d.ts" />

class Provider {
  private baseUrl = "https://aniwatchtv.to";

  getSettings(): Settings {
    return {
      episodeServers: ["MegaCloud", "VidSrc", "T-Cloud"],
      supportsDub: true,
    };
  }

  async search(query: SearchOptions): Promise<SearchResult[]> {
    // --- normalize helpers ---
    const normalize = (title) => {
      return (title || "")
        .toLowerCase()
        .replace(/(season|cour|part)/g, "")
        .replace(/\d+(st|nd|rd|th)/g, (m) => m.replace(/st|nd|rd|th/, ""))
        .replace(/[^a-z0-9]+/g, "")
        .replace(/(?<!i)ii(?!i)/g, "2");
    };

    const normalizeTitle = (title) => {
      return (title || "")
        .toLowerCase()
        .replace(/(season|cour|part|uncensored)/g, "")
        .replace(/\d+(st|nd|rd|th)/g, (m) => m.replace(/st|nd|rd|th/, ""))
        .replace(/[^a-z0-9]+/g, "");
    };

    const levenshteinSimilarity = (a, b) => {
      const lenA = a.length;
      const lenB = b.length;
      const dp = Array.from({ length: lenA + 1 }, () => new Array(lenB + 1).fill(0));

      for (let i = 0; i <= lenA; i++) dp[i][0] = i;
      for (let j = 0; j <= lenB; j++) dp[0][j] = j;

      for (let i = 1; i <= lenA; i++) {
        for (let j = 1; j <= lenB; j++) {
          if (a[i - 1] === b[j - 1]) dp[i][j] = dp[i - 1][j - 1];
          else dp[i][j] = 1 + Math.min(dp[i - 1][j], dp[i][j - 1], dp[i - 1][j - 1]);
        }
      }

      const distance = dp[lenA][lenB];
      const maxLen = Math.max(lenA, lenB);
      return 1 - distance / maxLen;
    };

    const start = query.media.startDate;
    const targetNormJP = normalize(query.media.romajiTitle);
    const targetNorm = query.media.englishTitle
      ? normalize(query.media.englishTitle)
      : targetNormJP;

    // Search via HTML scraping
    const searchUrl = `${this.baseUrl}/search?keyword=${encodeURIComponent(query.query)}`;
    const html = await fetch(searchUrl, {
      headers: {
        "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36",
        "Accept": "text/html,application/xhtml+xml,application/xml;q=0.9,image/webp,*/*;q=0.8",
        "Referer": this.baseUrl + "/",
      },
    }).then(res => res.text());

    // Parse search results from HTML
    const results: any[] = [];
    const itemRegex = /<a[^>]*href="\/([^"]+)-(\d+)(?:\?ref=search)?"[^>]*title="([^"]+)"[^>]*>/gi;
    let match;

    while ((match = itemRegex.exec(html)) !== null) {
      const slug = match[1];
      const id = match[2];
      const title = match[3].replace(/&#39;/g, "'").replace(/&amp;/g, "&");

      // Check for dub indicators in nearby HTML
      const hasDub = html.includes(`/${slug}-${id}`) && 
                     (html.includes('class="tick dub"') || html.includes('tick-dub'));

      results.push({
        id: id,
        slug: slug,
        title: title,
        normTitle: normalize(title),
        hasDub: hasDub,
      });
    }

    // Remove duplicates
    const uniqueResults = results.filter((item, index, self) =>
      index === self.findIndex((t) => t.id === item.id)
    );

    // Filter results
    let filtered = uniqueResults;

    // If dub requested, try to find dub version (but don't exclude if not found)
    if (query.dub) {
      const dubResults = uniqueResults.filter(m => m.hasDub);
      if (dubResults.length > 0) {
        filtered = dubResults;
      }
    }

    // Title matching
    const exactTitle = (m) =>
      m.normTitle === targetNorm ||
      m.normTitle === targetNormJP;

    const looseTitle = (m) =>
      levenshteinSimilarity(m.normTitle, targetNorm) > 0.8 ||
      levenshteinSimilarity(m.normTitle, targetNormJP) > 0.8 ||
      m.normTitle.includes(targetNorm) ||
      targetNorm.includes(m.normTitle);

    // Try exact match first
    let matched = filtered.filter(exactTitle);
    if (!matched.length) {
      matched = filtered.filter(looseTitle);
    }
    if (!matched.length) {
      matched = filtered;
    }

    // Sort by title similarity
    matched.sort((a, b) => {
      const simA = levenshteinSimilarity(a.normTitle, targetNorm);
      const simB = levenshteinSimilarity(b.normTitle, targetNorm);
      return simB - simA;
    });

    return matched.map(m => ({
      id: `${m.id}/${query.dub ? "dub" : "sub"}`,
      title: m.title,
      url: `${this.baseUrl}/${m.slug}-${m.id}`,
      subOrDub: query.dub ? "dub" : "sub",
    }));
  }

  async findEpisodes(Id: string): Promise<Episode[]> {
    const [id, subOrDub] = Id.split("/");

    // Fetch episode list via AJAX API
    const epRes = await fetch(
      `${this.baseUrl}/ajax/v2/episode/list/${id}`,
      {
        headers: {
          "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36",
          "Accept": "application/json",
          "X-Requested-With": "XMLHttpRequest",
          "Referer": `${this.baseUrl}/`,
        },
      }
    );

    const epJson = await epRes.json();
    const html = epJson?.html || "";

    // Parse episodes from HTML
    const episodes: Episode[] = [];
    const epRegex = /data-number="(\d+)"[^>]*data-id="(\d+)"[^>]*>.*?data-jname="([^"]*)"/gis;
    let match;

    while ((match = epRegex.exec(html)) !== null) {
      const epNumber = parseInt(match[1]);
      const epId = match[2];
      const epTitle = match[3].replace(/&#39;/g, "'").replace(/&amp;/g, "&");

      episodes.push({
        id: `${id}/${subOrDub}/${epId}`,
        number: epNumber,
        title: epTitle,
        url: `${this.baseUrl}/watch/${id}?ep=${epId}`,
      });
    }

    return episodes.sort((a, b) => a.number - b.number);
  }

  async findEpisodeServer(episode: EpisodeDetails, _server: string): Promise<EpisodeServer> {
    const parts = episode.id.split("/");
    const animeId = parts[0];
    const subOrDub = parts[1];
    const episodeId = parts[2];

    // Fetch server list
    const serversRes = await fetch(
      `${this.baseUrl}/ajax/v2/episode/servers?episodeId=${episodeId}`,
      {
        headers: {
          "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36",
          "Accept": "application/json",
          "X-Requested-With": "XMLHttpRequest",
          "Referer": `${this.baseUrl}/`,
        },
      }
    );

    const serversJson = await serversRes.json();
    const serversHtml = serversJson?.html || "";

    // Map server names to IDs
    const serverMap: Record<string, string> = {
      "MegaCloud": "1",
      "VidSrc": "4",
      "T-Cloud": "6",
    };

    const targetServerId = serverMap[_server] || "1";
    const targetType = subOrDub;

    // Parse server data-id from HTML
    const serverRegex = new RegExp(
      `data-type="${targetType}"[^>]*data-id="(\\d+)"[^>]*data-server-id="${targetServerId}"`,
      "i"
    );
    const serverMatch = serversHtml.match(serverRegex);

    if (!serverMatch) {
      throw new Error(`Server ${_server} not found for ${targetType}`);
    }

    const sourceId = serverMatch[1];

    // Fetch source/embed link
    const sourceRes = await fetch(
      `${this.baseUrl}/ajax/v2/episode/sources?id=${sourceId}`,
      {
        headers: {
          "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36",
          "Accept": "application/json",
          "X-Requested-With": "XMLHttpRequest",
          "Referer": `${this.baseUrl}/`,
        },
      }
    );

    const sourceJson = await sourceRes.json();
    const embedUrl = sourceJson?.link;

    if (!embedUrl) {
      throw new Error("No embed link found");
    }

    // Extract video from MegaCloud embed
    let decryptData = null;
    try {
      decryptData = await extractMegaCloud(embedUrl);
    } catch (err) {
      console.warn("Primary decrypter failed:", err);
    }

    // Fallback to ShadeOfChaos if primary fails
    if (!decryptData) {
      console.warn("Primary decrypter failed — trying ShadeOfChaos fallback...");
      const fallbackRes = await fetch(
        `https://ac-api.ofchaos.com/api/anime/embed/convert/v2?embedUrl=${encodeURIComponent(embedUrl)}`
      );
      decryptData = await fallbackRes.json();
    }

    if (!decryptData) {
      throw new Error("No video sources from any decrypter");
    }

    // Get HLS or MP4 stream
    const streamSource =
      decryptData.sources.find((s: any) => s.type === "hls") ||
      decryptData.sources.find((s: any) => s.type === "mp4") ||
      decryptData.sources[0];

    if (!streamSource?.file) {
      throw new Error("No valid stream file found");
    }

    // Map subtitles
    const subtitles =
      (decryptData.tracks || [])
        .filter((t: any) => t.kind === "captions")
        .map((track: any, index: number) => ({
          id: `sub-${index}`,
          language: track.label || "Unknown",
          url: track.file,
          isDefault: !!track.default,
        }));

    return {
      server: _server,
      headers: {
        "Referer": "https://megacloud.blog/",
        "Origin": "https://megacloud.blog",
        "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/139.0.0.0 Safari/537.36",
      },
      videoSources: [
        {
          url: streamSource.file,
          type: streamSource.type || "hls",
          quality: "auto",
          subtitles,
        },
      ],
    };
  }
}

async function extractMegaCloud(embedUrl: string) {
  const url = new URL(embedUrl);
  const baseDomain = `${url.protocol}//${url.host}/`;

  const headers = {
    "Accept": "*/*",
    "X-Requested-With": "XMLHttpRequest",
    "Referer": baseDomain,
    "User-Agent": "Mozilla/5.0 (Linux; Android 10; K) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/137.0.0.0 Mobile Safari/537.36",
  };

  // Fetch embed page
  const html = await fetch(embedUrl, { headers }).then((r) => r.text());

  // Extract file ID
  const fileIdMatch = html.match(/<title>\s*File\s+#([a-zA-Z0-9]+)\s*-/i);
  if (!fileIdMatch) throw new Error("file_id not found in embed page");
  const fileId = fileIdMatch[1];

  // Extract nonce
  let nonce: string | null = null;
  const match48 = html.match(/\b[a-zA-Z0-9]{48}\b/);
  if (match48) nonce = match48[0];
  else {
    const match3x16 = [...html.matchAll(/["']([A-Za-z0-9]{16})["']/g)];
    if (match3x16.length >= 3) {
      nonce = match3x16[0][1] + match3x16[1][1] + match3x16[2][1];
    }
  }
  if (!nonce) throw new Error("nonce not found");

  // Fetch sources
  const sourcesJson = await fetch(
    `${baseDomain}embed-2/v3/e-1/getSources?id=${fileId}&_k=${nonce}`,
    { headers }
  ).then((r) => r.json());

  return {
    sources: sourcesJson.sources,
    tracks: sourcesJson.tracks || [],
    intro: sourcesJson.intro || null,
    outro: sourcesJson.outro || null,
    server: sourcesJson.server || null,
  };
}
